const task = $json;
const d = new Date(task.due_date);
const timeStr = d.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Bogota' });
const dateStr = d.toLocaleDateString('es-CO', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'America/Bogota' });
const desc = task.description ? '\n📝 ' + task.description : '';
const msg = '⏰ *RECORDATORIO*\n\n📌 ' + task.title + desc + '\n🕐 ' + timeStr + ' - ' + dateStr + '\n\n_Este es un recordatorio automatico de Axon Prime_';
return { json: { message: msg, phone: task.phone, taskId: task.id, recurrence: task.recurrence } };

